  if (tokenTypeName == "eof") {
    // 找到最后一个非 EOF token
    size_t lastRealTokenIdx = tokenIndex;
    while (lastRealTokenIdx > 0) {
      auto checkToken = tokens.get(lastRealTokenIdx - 1);
      auto checkType = std::string(vocabulary.getSymbolicName(checkToken->getType()));
      if (checkType != "EOF" && checkType != "Newline") {
        line = checkToken->getLine() - lineOffset;
        col = checkToken->getCharPositionInLine() + 1 + checkToken->getText().length();
        break;
      }
      lastRealTokenIdx--;
    }
  }

  std::string locInfo = " Loc=<" + filename + ":" + std::to_string(line) + ":" + std::to_string(col) + ">";

