void
print_token(const antlr4::Token* token,
            const antlr4::CommonTokenStream& tokens,
            std::ofstream& outFile,
            const antlr4::Lexer& lexer)
{
  auto& vocabulary = lexer.getVocabulary();

  auto tokenTypeName =
    std::string(vocabulary.getSymbolicName(token->getType()));

  if (tokenTypeName.empty())
    tokenTypeName = "<UNKNOWN>"; // 处理可能的空字符串情况

  // 跳过 LineAfterPreprocessing, Whitespace, Newline token
  if (tokenTypeName == "LineAfterPreprocessing" || 
      tokenTypeName == "Whitespace" || 
      tokenTypeName == "Newline") {
    return;
  }

  if (tokenTypeMapping.find(tokenTypeName) != tokenTypeMapping.end()) {
    tokenTypeName = tokenTypeMapping[tokenTypeName];
  }

  // 获取 token 在 token stream 中的索引
  size_t tokenIndex = token->getTokenIndex();

  // 检查是否是行首（StartOfLine）
  // StartOfLine = token 前面只有空白符和换行符，直到行首
  // EOF token 永远不会有 StartOfLine
  bool startOfLine = false;
  if (tokenTypeName != "eof" && tokenIndex > 0) {
    // 检查从上一个换行符或开头到当前 token 之间是否只有空白符
    bool onlyWhitespaceSinceNewline = true;
    for (size_t i = tokenIndex; i > 0; i--) {
      auto checkToken = tokens.get(i - 1);
      auto checkType = std::string(vocabulary.getSymbolicName(checkToken->getType()));
      // std::cerr << "Checking token " << i-1 << ": " << checkType << " '" << checkToken->getText() << "'" << std::endl;
      if (checkType == "Newline") {
        // 找到了换行符，说明当前 token 在行首
        startOfLine = true;
        break;
      } else if (checkType != "Whitespace" && checkType != "LineAfterPreprocessing") {
        // 找到了非空白、非换行、非预处理指令的 token
        onlyWhitespaceSinceNewline = false;
        break;
      }
    }
    // 如果遍历到开头都没有找到换行符，但只有空白符，说明这是文件的第一个 token
    // 这种情况也算在行首
    if (onlyWhitespaceSinceNewline) {
      startOfLine = true;
    }
  } else if (tokenTypeName != "eof") {
    // 第一个 token
    startOfLine = true;
  }

  // 检查是否有前导空格（LeadingSpace）
  // LeadingSpace = token 前面紧跟着空白符
  bool leadingSpace = false;
  if (tokenIndex > 0) {
    auto prevToken = tokens.get(tokenIndex - 1);
    auto prevTokenType = std::string(vocabulary.getSymbolicName(prevToken->getType()));
    // 如果前一个 token 是空白符
    if (prevTokenType == "Whitespace") {
      leadingSpace = true;
    }
  }

  // 构建位置信息
  std::string filename = currentFilename.empty() ? "<unknown>" : currentFilename;
  // ANTLR 行号从1开始，我们需要减去 lineOffset 得到实际行号
  int line = token->getLine() - lineOffset;
  int col = token->getCharPositionInLine() + 1;

  // EOF token 的特殊处理：行号应该是最后一行的行号，列号是最后一列+1
  if (tokenTypeName == "eof") {
    // 找到最后一个非 EOF token
    size_t lastRealTokenIdx = tokenIndex;
    while (lastRealTokenIdx > 0) {
      auto checkToken = tokens.get(lastRealTokenIdx - 1);
      auto checkType = std::string(vocabulary.getSymbolicName(checkToken->getType()));
      if (checkType != "EOF" && checkType != "Newline") {
        line = checkToken->getLine() - lineOffset;
        col = checkToken->getCharPositionInLine() + 1 + checkToken->getText().length();
        break;
      }
      lastRealTokenIdx--;
    }
  }

  std::string locInfo = " Loc=<" + filename + ":" + std::to_string(line) + ":" + std::to_string(col) + ">";

  if (token->getText() != "<EOF>")
    outFile << tokenTypeName << " '" << token->getText() << "'";
  else
    outFile << tokenTypeName << " '"
            << "'";
  // 根据 clang 的格式：
  // - 如果有 StartOfLine，输出 \t [StartOfLine]
  // - 如果有 LeadingSpace，输出 \t [LeadingSpace]
  // - 如果都没有，输出 \t\t
  if (startOfLine && leadingSpace) {
    outFile << "\t [StartOfLine] [LeadingSpace]";
  } else if (startOfLine) {
    outFile << "\t [StartOfLine]";
  } else if (leadingSpace) {
    outFile << "\t [LeadingSpace]";
  } else {
    outFile << "\t\t";
  }
  outFile << locInfo << std::endl;
}

// 从预处理指令中提取文件名
// 格式: # linenum filename flags
void extractFilenameFromLine(const std::string& line, int antlrLineNum) {
  // 匹配 # linenum "filename" 或 # linenum filename
  std::regex lineDirectiveRegex("^#\\s+(\\d+)\\s+\"([^\"]+)\".*");
  std::regex lineDirectiveRegex2("^#\\s+(\\d+)\\s+(\\S+).*");
  std::smatch match;

  if (std::regex_match(line, match, lineDirectiveRegex)) {
    int actualLineNum = std::stoi(match[1].str());
    std::string filename = match[2].str();
    // 只处理非 <built-in> 和 <command line> 的文件
    if (filename[0] != '<') {
      // lineOffset = (ANTLR行号+1) - 实际行号
      // 预处理指令在ANTLR行号N，下一行(ANTLR行号N+1)对应实际行号actualLineNum
      int lineOffset = (antlrLineNum + 1) - actualLineNum;
      fileMappings.push_back({antlrLineNum + 1, filename, lineOffset});
    }
  } else if (std::regex_match(line, match, lineDirectiveRegex2)) {
    int actualLineNum = std::stoi(match[1].str());
    std::string filename = match[2].str();
    if (filename[0] != '<') {
      int lineOffset = (antlrLineNum + 1) - actualLineNum;
      fileMappings.push_back({antlrLineNum + 1, filename, lineOffset});
    }
  }
}

// 根据 ANTLR 行号查找对应的文件名和 lineOffset
std::pair<std::string, int> getFileInfo(int antlrLine) {
  // 从后向前查找，找到第一个起始行号 <= antlrLine 的条目
  for (int i = fileMappings.size() - 1; i >= 0; i--) {
    if (fileMappings[i].antlrStartLine <= antlrLine) {
      return {fileMappings[i].filename, fileMappings[i].lineOffset};
    }
  }
  return {defaultFilename, 0};
}

