void
EmitIR::operator()(VarDecl* obj)
{
  // 全局变量
  if (mCurFunc == nullptr) {
    auto type = self(obj->type);
    auto gv = new llvm::GlobalVariable(
      mMod,
      type,
      false,
      llvm::GlobalValue::ExternalLinkage,
      nullptr,
      obj->name);

    if (obj->init) {
      if (auto initVal = llvm::dyn_cast<llvm::Constant>(self(obj->init))) {
        gv->setInitializer(initVal);
      }
    }
    obj->any = gv;
  }
  // 局部变量
  else {
    auto type = self(obj->type);
    auto alloca = mCurIrb->CreateAlloca(type, nullptr, obj->name);
    obj->any = alloca;

    if (obj->init) {
      auto initVal = self(obj->init);
      mCurIrb->CreateStore(initVal, alloca);
    }
  }
}

