     6	isAllocaPromotable(const AllocaInst* AI)
     7	{
     8	  // Only allow direct and non-volatile loads and stores...
     9	  for (const User* U : AI->users()) {
    10	    if (const LoadInst* LI = dyn_cast<LoadInst>(U)) {
    11	      // Note that atomic loads can be transformed; atomic semantics do
    12	      // not have any meaning for a local alloca.
    13	      if (LI->getType() != AI->getAllocatedType())
    14	        return false;
    15	    } else if (const StoreInst* SI = dyn_cast<StoreInst>(U)) {
    16	      if (SI->getValueOperand() == AI ||
    17	          SI->getValueOperand()->getType() != AI->getAllocatedType())
    18	        return false; // Don't allow a store OF the AI, only INTO the AI.
    19	      // Note that atomic stores can be transformed; atomic semantics do
    20	      // not have any meaning for a local alloca.
    21	    } else {
    22	      return false;
    23	    }
    24	  }
