   474	PreservedAnalyses
   475	Mem2Reg::run(llvm::Module& mod, llvm::ModuleAnalysisManager& mam)
   476	{
   477	
   478	  FunctionAnalysisManager fam;
   479	  PassBuilder pb;
   480	  pb.registerFunctionAnalyses(fam);
   481	  bool flag = true;
   482	  for (Function& func : mod) {
   483	    if (func.isDeclaration())
   484	      continue;
   485	    auto& DT = fam.getResult<DominatorTreeAnalysis>(func);
   486	    if (promoteMemoryToRegister(func, DT)) {
   487	      flag = false;
   488	    }
   489	  }
   490	  if (flag) {
   491	    return PreservedAnalyses::all();
   492	  }
   493	  PreservedAnalyses PA;
   494	  PA.preserveSet<CFGAnalyses>();
   495	  return PA;
   496	}
